function brentq(f, a, b, args, tol = 1e-10, maxIter = 200) {
  let fa = f(a, ...args), fb = f(b, ...args);
  if (fa * fb &gt; 0) return NaN;
  if (Math.abs(fa) &lt; Math.abs(fb)) { [a, b] = [b, a]; [fa, fb] = [fb, fa]; }
  let c = a, fc = fa, mflag = true, s, d;
  for (let i = 0; i &lt; maxIter; i++) {
    if (Math.abs(b - a) &lt; tol) return b;
    if (fa !== fc && fb !== fc) {
      s = a*fb*fc/((fa-fb)*(fa-fc))
        + b*fa*fc/((fb-fa)*(fb-fc))
        + c*fa*fb/((fc-fa)*(fc-fb));
    } else {
      s = b - fb*(b-a)/(fb-fa);
    }
    const cond1 = !((3*a+b)/4 &lt; s && s &lt; b || b &lt; s && s &lt; (3*a+b)/4);
    const cond2 = mflag  && Math.abs(s-b) &gt;= Math.abs(b-c)/2;
    const cond3 = !mflag && Math.abs(s-b) &gt;= Math.abs(c-d)/2;
    const cond4 = mflag  && Math.abs(b-c) &lt; tol;
    const cond5 = !mflag && Math.abs(c-d) &lt; tol;
    if (cond1||cond2||cond3||cond4||cond5) { s=(a+b)/2; mflag=true; }
    else { mflag=false; }
    const fs = f(s, ...args);
    d=c; c=b; fc=fb;
    if (fa*fs &lt; 0) { b=s; fb=fs; } else { a=s; fa=fs; }
    if (Math.abs(fa) &lt; Math.abs(fb)) { [a,b]=[b,a]; [fa,fb]=[fb,fa]; }
  }
  return b;
}

// Sphere transcendental: 1 − ζ cot(ζ) − Bi = 0
function transcendental(zeta, Bi) {
  return 1.0 - zeta / Math.tan(zeta) - Bi;
}

// Fourier coefficient C_n
function coeff(zeta) {
  return 4*(Math.sin(zeta) - zeta*Math.cos(zeta))
         / (2*zeta - Math.sin(2*zeta));
}

// First N positive roots of the transcendental equation
function getRoots(Bi, N = 50) {
  const roots = [];
  for (let n = 1; n &lt;= N; n++) {
    const lo = (n-1)*Math.PI + 1e-9;
    const hi =  n   *Math.PI - 1e-9;
    const z = brentq(transcendental, lo, hi, [Bi]);
    if (!isNaN(z)) roots.push(z);
  }
  return roots;
}

// Evaluate dimensionless temperature profile along r*
function thetaProfile(rArr, roots, Cn, Fo) {
  return rArr.map(r =&gt; {
    let sum = 0;
    for (let i = 0; i &lt; roots.length; i++) {
      const z = roots[i];
      const decay   = Cn[i] * Math.exp(-z*z*Fo);
      const spatial = r &lt; 1e-10 ? 1.0 : Math.sin(z*r)/(z*r);
      sum += decay * spatial;
    }
    return Math.max(0, sum);
  });
}

// ── Compute everything ────────────────────────────────────────────────────────

N_PTS  = 300
r_star = Array.from({length: N_PTS}, (_, i) =&gt; i / (N_PTS - 1))

roots  = getRoots(Bi, 50)
Cn_all = roots.map(coeff)

theta_full    = thetaProfile(r_star, roots,          Cn_all,          Fo)
theta_oneterm = thetaProfile(r_star, roots.slice(0,1), Cn_all.slice(0,1), Fo)
theta_lumped  = r_star.map(() =&gt; Math.exp(-Bi * Fo))   // horizontal line

// Pack into Plot-friendly row arrays
full_rows    = r_star.map((r,i) =&gt; ({r, theta: theta_full[i],    series: "Full series (N=50)"}))
oneterm_rows = r_star.map((r,i) =&gt; ({r, theta: theta_oneterm[i], series: "One-term"}))
lumped_rows  = r_star.map((r,i) =&gt; ({r, theta: theta_lumped[i],  series: "Lumped"}))
